import{_ as s,o as a,c as i,aq as t}from"./chunks/framework.DH0nG2Fl.js";const u=JSON.parse('{"title":"First Edits","description":"","frontmatter":{"prev":{"text":"Your First Extension","link":"/development/extensions/start"},"next":{"text":"Main.ts","link":"/development/extensions/main.ts"}},"headers":[],"relativePath":"development/extensions/first-edits.md","filePath":"development/extensions/first-edits.md","lastUpdated":1782516350000}'),n={name:"development/extensions/first-edits.md"};function o(l,e,r,h,d,p){return a(),i("div",null,[...e[0]||(e[0]=[t(`<h1 id="first-edits" tabindex="-1">First Edits <a class="header-anchor" href="#first-edits" aria-label="Permalink to “First Edits”">​</a></h1><p>In this guide we will look at the files common to all extensions, then edit them to make this extension our own.</p><h2 id="how-does-an-extension-work" tabindex="-1">How does an extension work? <a class="header-anchor" href="#how-does-an-extension-work" aria-label="Permalink to “How does an extension work?”">​</a></h2><p>Here is what the file tree of an extension looks like:</p><div class="language-txt"><button title="Copy Code" class="copy"></button><span class="lang">txt</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>./static</span></span>
<span class="line"><span>./static/icon.png</span></span>
<span class="line"><span>./content.json</span></span>
<span class="line"><span>./forms.ts</span></span>
<span class="line"><span>./main.ts</span></span>
<span class="line"><span>./models.ts</span></span>
<span class="line"><span>./network.ts</span></span>
<span class="line"><span>./pbconfig.ts</span></span></code></pre></div><p>When a user first downloads your extension, Paperback needs some basic information about it. That is what <code>pbconfig.ts</code> is for.</p><h3 id="pbconfig-ts" tabindex="-1">pbconfig.ts <a class="header-anchor" href="#pbconfig-ts" aria-label="Permalink to “pbconfig.ts”">​</a></h3><p>This file exports a single object satisfying the <code>ExtensionInfo</code> type, which summarises all the surface-level metadata of the extension.</p><h4 id="name" tabindex="-1">Name <a class="header-anchor" href="#name" aria-label="Permalink to “Name”">​</a></h4><p>The <code>name</code> field is the display name of your extension. Spaces are allowed, but it is cleaner to avoid them. The name should also match the directory where the code lives. Do not use the raw domain as the name:</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>anilist.co   --&gt;   AniList</span></span></code></pre></div><h4 id="description" tabindex="-1">Description <a class="header-anchor" href="#description" aria-label="Permalink to “Description”">​</a></h4><p>Technically you can write anything here, but the Inkdex convention is:</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>Extension that pulls content from anilist.co.</span></span></code></pre></div><h4 id="version" tabindex="-1">Version <a class="header-anchor" href="#version" aria-label="Permalink to “Version”">​</a></h4><p>The <code>version</code> string matters more than it might seem. Paperback allows updating between any two extensions that share the same name, as long as their version strings differ, even if the new version string is actually lower. This means you could accidentally downgrade an extension if you are not careful.</p><p>A common scenario: you may have the same extension in multiple places (your local machine, a stable GitHub release, etc.) with different version numbers. Be cautious when prompted to update.</p><p>Note that you do not need to bump the version every time you want to test something on your phone. Simply hit reload and it will reinstall.</p><p>At Inkdex, the first published version of an extension on an official repo starts at <code>v1.0.0-alpha.1</code>.</p><h4 id="icon" tabindex="-1">Icon <a class="header-anchor" href="#icon" aria-label="Permalink to “Icon”">​</a></h4><p>The Paperback type definition explains this field well:</p><blockquote><p>An INTERNAL reference to an icon which is associated with this source. This Icon should ideally be a matching aspect ratio (a cube). The location of this should be in an includes directory next to your source.</p><p>(<code>@paperback/type/lib/impl/SourceInfo.d.ts:86</code>)</p></blockquote><p>In practice: create a <code>static/</code> directory inside your extension folder, place your icon there, and set the <code>icon</code> field to just the filename (not the full path).</p><p>At Inkdex, we prefer square PNGs with a simple logo, not the full website name.</p><h4 id="language" tabindex="-1">Language <a class="header-anchor" href="#language" aria-label="Permalink to “Language”">​</a></h4><p>Not strictly required, but trivial to add. Use lowercase <a href="https://www.loc.gov/standards/iso639-2/php/code_list.php" target="_blank" rel="noreferrer">ISO 639-1</a> codes:</p><ul><li><code>en</code> -- English-only content</li><li><code>es</code> -- Spanish-only content</li><li><code>multi</code> -- multiple languages</li></ul><h4 id="content-rating" tabindex="-1">Content Rating <a class="header-anchor" href="#content-rating" aria-label="Permalink to “Content Rating”">​</a></h4><p>The Paperback type definition covers this clearly:</p><blockquote><p>A content rating attributed to each source. This can be one of three values, and should be set appropriately.</p><ul><li><strong>Everyone:</strong> This source does not have any sort of adult content available. Each title within is assumed safe for all audiences.</li><li><strong>Mature:</strong> This source MAY have mature content inside of it. Even if most content is safe, Mature should be selected if even a small subset applies.</li><li><strong>Adult:</strong> This source probably has straight up pornography available.</li></ul><p>This rating helps us filter your source to users who have the necessary visibility rules toggled for their profile. Naturally, only &#39;Everyone&#39; sources will show up for users without an account, or without any mode toggles changed.</p><p>(<code>@paperback/type/lib/impl/SourceInfo.d.ts:101</code>)</p></blockquote><h4 id="capabilities" tabindex="-1">Capabilities <a class="header-anchor" href="#capabilities" aria-label="Permalink to “Capabilities”">​</a></h4><p>This is the most important field in the file. It is a list of <code>SourceIntents</code> enum values and dictates exactly what the extension can and cannot do:</p><ul><li><code>NONE</code> -- The extension does nothing.</li><li><code>CHAPTER_PROVIDING</code> -- The extension can read a chapter when asked to.</li><li><code>PROGRESS_PROVIDING</code> -- Can manage the user&#39;s reading progress to/from a website (often requires the user to be logged in).</li><li><code>DISCOVER_SECTION_PROVIDING</code> -- Can provide a homepage for the website in the Home section.</li><li><code>MANAGED_COLLECTION_PROVIDING</code> -- Lets you set up a Managed Collection that syncs to and from the website, where it can update reading lists, shelves, categories, etc. (also often requires login).</li><li><code>CLOUDFLARE_BYPASS_PROVIDING</code> -- The extension can use the built-in CloudFlare bypassing tools.</li><li><code>SETTINGS_FORM_PROVIDING</code> -- The extension exposes a custom settings page called the Settings Form.</li><li><code>SEARCH_RESULT_PROVIDING</code> -- The extension supports searching, either with simple sorting or advanced filters.</li></ul><h4 id="badges" tabindex="-1">Badges <a class="header-anchor" href="#badges" aria-label="Permalink to “Badges”">​</a></h4><p>An array of <code>SourceBadge</code> objects. It can be empty and only affects how the extension is displayed on the repository website.</p><p>Inkdex does not use badges, but some repositories use them to distinguish between content types. For example, the <a href="https://catta1997.github.io/Sinon-Paperback-Extensions/0.9/stable/" target="_blank" rel="noreferrer">Sinon Extension Repo</a> uses a <code>Novel</code> tag with a dark green background, defined in their <a href="https://github.com/Catta1997/Sinon-Paperback-Extensions/blob/0.9/stable/src/LNori/pbconfig.ts" target="_blank" rel="noreferrer">pbconfig.ts</a> as:</p><div class="language-typescript"><button title="Copy Code" class="copy"></button><span class="lang">typescript</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">badges</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: [</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  {</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    label: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;Novel&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    textColor: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;#ffffff&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    backgroundColor: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;#3baf4b&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  },</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">],</span></span></code></pre></div><h4 id="developers" tabindex="-1">Developers <a class="header-anchor" href="#developers" aria-label="Permalink to “Developers”">​</a></h4><p>An array of <code>SourceDeveloper</code> objects. The list is shown both on the repository website and inside the app, so only include what you are comfortable making public.</p><p>Only <code>name</code> is required. Both a <code>website</code> and a GitHub link are optional, but if you provide both, only the <code>website</code> will be displayed. Multiple developers are supported.</p>`,40)])])}const g=s(n,[["render",o]]);export{u as __pageData,g as default};
